import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: String {
        switch self {
        case .development:
            return "https://dev-api.example.com"
        case .staging:
            return "https://staging-api.example.com"
        case .production:
            return "https://api.example.com"
        }
    }
}

final class NetworkManager {
    static let shared = NetworkManager()
    private let session = URLSession.shared
    private var environment: Environment = .development
    
    private init() {}
    
    func setEnvironment(_ environment: Environment) {
        self.environment = environment
    }
    
    func authenticate(username: String, password: String, completion: @escaping (Result<Data, Error>) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)/authenticate") else { return }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        
        let params = ["username": username, "password": password]
        request.httpBody = try? JSONSerialization.data(withJSONObject: params, options: [])
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            guard let data = data else { return }
            completion(.success(data))
        }.resume()
    }
    
    func fetchUserData(userId: String, completion: @escaping (Result<Data, Error>) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)/users/\(userId)") else { return }
        let request = URLRequest(url: url)
        
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            guard let data = data else { return }
            completion(.success(data))
        }.resume()
    }
}